import { NavLink, useNavigate } from 'react-router-dom';
import { useAuth } from '../../../hooks/useAuth.js';
import '../styles.css';

const navItems = {
  admin: [
    { to: '/admin', label: 'Dashboard' },
    { to: '/admin/users', label: 'Users' },
    { to: '/admin/reports', label: 'Reports' },
  ],
  mentor: [
    { to: '/mentor', label: 'Dashboard' },
    { to: '/mentor/review-queue', label: 'Review Queue' },
  ],
};

export default function AdminMentorLayout({ area, title, subtitle, children }) {
  const navigate = useNavigate();
  const { user, logout } = useAuth();
  const items = navItems[area] || navItems.admin;
  const roleLabel = area === 'mentor' ? 'Mentor' : 'Admin';

  const handleLogout = async () => {
    await logout();
    navigate('/auth/login', { replace: true });
  };

  return (
    <main className="admin-mentor-shell bg-light min-vh-100">
      <aside className="admin-mentor-sidebar bg-white border-end">
        <div className="px-3 py-4 border-bottom">
          <div className="d-flex align-items-center gap-2">
            <div className="admin-mentor-brand">OCP</div>
            <div>
              <strong className="d-block">{roleLabel}</strong>
              <span className="small text-secondary">Mentor Review + Admin</span>
            </div>
          </div>
        </div>

        <nav className="nav flex-column gap-1 p-3" aria-label={`${roleLabel} navigation`}>
          {items.map((item) => (
            <NavLink
              className={({ isActive }) =>
                `nav-link admin-mentor-nav-link ${isActive ? 'active' : ''}`
              }
              end={item.to === '/admin' || item.to === '/mentor'}
              key={item.to}
              to={item.to}
            >
              {item.label}
            </NavLink>
          ))}
        </nav>
      </aside>

      <section className="admin-mentor-content">
        <header className="admin-mentor-topbar bg-white border-bottom">
          <div>
            <p className="text-uppercase text-secondary small mb-1">{roleLabel} workspace</p>
            <h1 className="h3 mb-1">{title}</h1>
            {subtitle ? <p className="text-secondary mb-0">{subtitle}</p> : null}
          </div>

          <div className="d-flex align-items-center gap-3">
            {/* Luu y dong bo voi Member 1: identity/role/session lay tu AuthProvider va cookie httpOnly, khong doc token o frontend. */}
            <div className="text-end d-none d-sm-block">
              <strong className="d-block">{user?.name || roleLabel}</strong>
              <span className="small text-secondary">{user?.email || 'auth@ocp.local'}</span>
            </div>
            <button className="btn btn-outline-secondary btn-sm" onClick={handleLogout} type="button">
              Logout
            </button>
          </div>
        </header>

        <div className="container-fluid py-4">{children}</div>
      </section>
    </main>
  );
}
